/* ad::av — UConnect/RADIO_FGA CRC-16 seed-key algorithm (CRC-16 with poly 0x8408, init 0xFFFF). */
const AVC=0x8408;
function avCrc16(init,bytes){let c=init&0xFFFF;for(const b of bytes){let bb=b&0xFF;for(let i=0;i<8;i++){const bit=(c&1)^(bb&1);c>>>=1;if(bit)c^=AVC;c&=0xFFFF;bb>>>=1;}}return c;}
function avPerm(x){x&=0xFF;let r=0;r|=(0x40&(x<<6));r|=(0x10&(x<<3));r|=(0x02&(x>>>1));r|=(0x80&(x<<4));r|=(0x04&(x>>>2));r|=(0x01&(x>>>5));r|=(0x20&(x>>>1));r|=(0x08&(x>>>4));return r&0xFF;}
function alfaAV(s){
  const sb=Array.isArray(s)?s:[(s>>>24)&0xFF,(s>>>16)&0xFF,(s>>>8)&0xFF,s&0xFF];
  const v0=0x42,v1=0x95;  // precomputed: ror8(0x12,3)=0x42, 0x34^0xA1=0x95
  const v2=(sb[0]^0xDC)&0xFF, v5=(sb[3]^0x7A)&0xFF;
  const v3=avPerm(sb[1]);
  const v4=((((sb[2]<<8)|sb[2])^0xFFFF)>>>4)&0xFF;  // swap-nibbles of ~seed[2]
  const v8=avCrc16(0xFFFF,[v0,v4,v2]);
  const v9=avCrc16(0xFFFF,[v1,v3,v5]);
  return(((v8>>>8)&0xFF)<<24)|((v9&0xFF)<<16)|((v8&0xFF)<<8)|((v9>>>8)&0xFF);
}
