function PH({icon,title,sub}){return<Card style={{textAlign:'center',padding:'60px 24px'}}><div style={{fontSize:48,marginBottom:12,opacity:.3}}>{icon}</div><div style={{fontSize:20,fontWeight:900,color:C.tm}}>{title}</div><div style={{fontSize:13,color:C.tm,marginTop:4}}>{sub}</div></Card>;}/* ═══ SECURITY MATCHER TAB (Piece 4) ═══ */
function extractVAt(d,o){if(o+17>d.length)return null;let s='';for(let i=0;i<17;i++){const b=d[o+i];if(b<0x20||b>0x7E)return null;s+=String.fromCharCode(b);}return/^[1-9A-HJ-NPR-Z][A-HJ-NPR-Z0-9]{16}$/.test(s)?s:null;}
function secAnalyze(data,fn){const sz=data.length;const m={fn,sz,type:'?',vins:[],skey:null,skoff:-1,skb:true,immo:null,immoBak:null,immoOk:true,immoBlank:true,bak:null,bakBlank:true,fobBlank:true,raw:data};
  if(sz===65536||sz===131072){m.type='bcm';
    for(let i=0;i<=sz-19;i++){const v=extractVAt(data,i);if(!v)continue;let sum=0;for(let j=0;j<17;j++)sum+=(TR[v[j]]||0)*WT[j];if('0123456789X'[sum%11]!==v[8])continue;const sc=(data[i+17]<<8)|data[i+18],cc=crc16(data.slice(i,i+17));if(sc===cc){m.vins.push({off:i,vin:v});i+=16;}}
    const sb=data.slice(0x40C0,0x40E0);if(!sb.every(b=>b===0xFF)){m.immoBlank=false;m.immo=data.slice(0x40C8,0x40DA);m.immoBak=data.slice(0x40F0,0x4102);m.immoOk=true;for(let j=0;j<m.immo.length;j++)if(m.immo[j]!==m.immoBak[j]){m.immoOk=false;break;}}
    m.bakBlank=data.slice(0x2000,0x2020).every(b=>b===0xFF);if(!m.bakBlank)m.bak=data.slice(0x2000,0x2020);
  }else if(sz===8192||sz===16384){m.type='95640';
    for(const o of[0x275,0x288]){const v=extractVAt(data,o);if(v)m.vins.push({off:o,vin:v});}
    m.skey=data.slice(0x40,0x50);m.skoff=0x40;m.skb=m.skey.every(b=>b===0xFF);m.fobBlank=data.slice(0x200,0x240).every(b=>b===0xFF);
  }else if(sz===4096){
    const v0=extractVAt(data,0);
    if(v0){m.type='gpec2a';for(const off of PCM_VIN_OFFSETS_GPEC2A){if(off===0)continue;const vN=extractVAt(data,off);if(vN)m.vins.push({off,vin:vN});}m.vins.unshift({off:0,vin:v0});}
    else{m.type='rfhub';for(const o of[0xEA5,0xEB9,0xECD,0xEE1]){if(o+17>sz)continue;const st=data.slice(o,o+17);if(st.every(b=>b===0xFF||b===0))continue;const rev=new Uint8Array(17);for(let j=0;j<17;j++)rev[j]=st[16-j];m.vins.push({off:o,vin:String.fromCharCode(...rev),mir:true});break;}
      m.skey=data.slice(0x40,0x50);m.skoff=0x40;m.skb=m.skey.every(b=>b===0xFF);}
  }return m;}

const SKLBL={bcm:'BCM D-FLASH','95640':'FCA 95640',rfhub:'RFHUB EEE',gpec2a:'GPEC2A'};
const SKCOL={bcm:C.a1,'95640':C.a4,rfhub:C.a3,gpec2a:C.a2};
const SKIM_OFF=[{v:'Trackhawk',base:0x2000,ks:18,kc:6},{v:'SRT',base:0x40C0,ks:18,kc:6}];

const SKIM_GEN_NOTES = {
  'gen1-18b':   { label:'Gen1 · 18-byte SEC format', color:'#2979FF', notes:['Standard SKIM protocol (18-byte SEC16 record)','Key programming does not require RFHUB pre-sync','BCM secret key at fixed 0x40C0 block'] },
  'gen2-split': { label:'Gen2 · SEC16 split format',  color:'#FF6D00', notes:['Gen2 requires RFHUB SEC16 sync before key programming','BCM and RFHUB must share matching secret key after any swap','SEC16 record is split across two BCM flash regions'] },
  'trackhawk-no-flash': { label:'Trackhawk · no BCM flash', color:'#00BFA5', notes:['BCM is not flash-programmed — dealer J2534 only for key adds','SKIM secret key lives in the RFHUB 95640 EEPROM','VIN patch via 95640 drop; BCM follows from RFH sync'] },
};

function SkimVehicleBanner({vehicle}){
  if(!vehicle) return null;
  const gens = vehicle.generations ?? [];
  const sec16Types = [...new Set(gens.map(g=>g.sec16).filter(Boolean))];
  return(
    <div style={{marginBottom:14,borderRadius:12,overflow:'hidden',border:'1px solid '+C.bd}}>
      <div style={{padding:'10px 14px',background:C.c2,display:'flex',alignItems:'center',gap:10,borderBottom:'1px solid '+C.bd}}>
        <span style={{fontSize:20}}>🛡️</span>
        <div>
          <div style={{fontSize:13,fontWeight:900,letterSpacing:1,color:C.tx}}>{vehicle.full ?? vehicle.name}</div>
          <div style={{fontSize:10,color:C.tm,fontWeight:700,letterSpacing:1}}>{vehicle.body}</div>
        </div>
        <div style={{marginLeft:'auto',display:'flex',gap:6,flexWrap:'wrap'}}>
          {gens.map(g=><span key={g.id} style={{padding:'3px 9px',borderRadius:6,fontSize:9,fontWeight:800,background:C.bd,color:C.ts,letterSpacing:1}}>{g.label}</span>)}
        </div>
      </div>
      {sec16Types.map(st=>{
        const info = SKIM_GEN_NOTES[st];
        if(!info) return null;
        return(
          <div key={st} style={{padding:'9px 14px',borderBottom:'1px solid '+C.bd,background:C.cd}}>
            <div style={{fontSize:10,fontWeight:900,color:info.color,letterSpacing:1,marginBottom:4}}>{info.label}</div>
            <ul style={{margin:0,paddingLeft:16,listStyle:'disc'}}>
              {info.notes.map((n,i)=><li key={i} style={{fontSize:10,color:C.ts,marginBottom:2}}>{n}</li>)}
            </ul>
          </div>
        );
      })}
    </div>
  );
}

function SkimSecurityTab({vehicle}){
  const[mods,setMods]=useState([]);const[tv,setTv]=useState('');const[msg,setMsg]=useState('');
  const addF=useCallback(fl=>{Promise.all(Array.from(fl).map(f=>new Promise(r=>{const rd=new FileReader();rd.onload=e=>{const d=new Uint8Array(e.target.result);const m=secAnalyze(d,f.name);r(m.type!=='?'?m:null);};rd.readAsArrayBuffer(f);}))).then(res=>{const v=res.filter(Boolean);setMods(p=>{const u=[...p,...v];if(!tv&&u.length)for(const m of u)if(m.vins.length){setTv(m.vins[0].vin);break;}return u;});});},[tv]);
  const allV=useMemo(()=>{const s=new Set();mods.forEach(m=>m.vins.forEach(v=>s.add(v.vin)));return[...s];},[mods]);
  const vinBad=allV.length>1;
  const sks=useMemo(()=>mods.filter(m=>m.skey&&!m.skb).map(m=>({idx:mods.indexOf(m),type:m.type,key:m.skey,fn:m.fn})),[mods]);
  const skBad=useMemo(()=>{if(sks.length<2)return false;for(let i=1;i<sks.length;i++)for(let j=0;j<sks[0].key.length;j++)if(sks[0].key[j]!==sks[i].key[j])return true;return false;},[sks]);
  const skimG=useMemo(()=>{const bcm=mods.find(m=>m.type==='bcm');if(!bcm)return[];const r=[];for(const c of SKIM_OFF){if(c.base+c.ks*c.kc>bcm.sz)continue;const keys=[];let has=false;for(let i=0;i<c.kc;i++){const o=c.base+i*c.ks;const kb=bcm.raw.slice(o,o+c.ks);const hex=hxb(kb);if(!kb.every(b=>b===0xFF||b===0))has=true;keys.push({slot:i+1,off:o,hex,empty:kb.every(b=>b===0xFF||b===0)});}if(has)r.push({v:c.v,keys,base:c.base});}return r;},[mods]);
  const dl=(d,n)=>{const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([d]));a.download=n;a.click();};
  function syncKey(si,ti){const s=mods[si],t=mods[ti];if(!s.skey||s.skb||t.skoff<0)return;const p=new Uint8Array(t.raw);for(let i=0;i<16;i++)p[t.skoff+i]=s.skey[i];dl(p,t.fn.replace(/\./,'_KEYSYNCED.'));setMsg('Key from '+s.fn+' → '+t.fn);}
  function patchV(i){if(tv.length!==17)return;const m=mods[i];const p=new Uint8Array(m.raw);const vb=new TextEncoder().encode(tv);
    if(m.type==='bcm'){m.vins.forEach(v=>{for(let j=0;j<17;j++)p[v.off+j]=vb[j];const c=crc16(vb);p[v.off+17]=(c>>8)&0xFF;p[v.off+18]=c&0xFF;});}
    else if(m.type==='95640'){[0x275,0x288].forEach(o=>{if(o+17>p.length)return;for(let j=0;j<17;j++)p[o+j]=vb[j];p[o-1]=crc8a(vb);});}
    else if(m.type==='rfhub'){const mr=[...vb].reverse();[0xEA5,0xEB9,0xECD,0xEE1].forEach(o=>{if(o+18>p.length)return;for(let j=0;j<17;j++)p[o+j]=mr[j];});}
    else if(m.type==='gpec2a'){PCM_VIN_OFFSETS_GPEC2A.forEach(o=>{if(o+17>p.length)return;for(let j=0;j<17;j++)p[o+j]=vb[j];});}
    dl(p,m.fn.replace(/\./,'_VIN_'+tv+'.'));setMsg('Patched '+SKLBL[m.type]+' → '+tv);}

  return<div>
    <SkimVehicleBanner vehicle={vehicle}/>
    {/* Drop zone */}
    <div onClick={()=>{const i=document.createElement('input');i.type='file';i.multiple=true;i.accept='.bin,.BIN';i.onchange=e=>addF(e.target.files);i.click();}} onDrop={e=>{e.preventDefault();addF(e.dataTransfer.files);}} onDragOver={e=>e.preventDefault()}>
      <Card style={{textAlign:'center',padding:'24px',cursor:'pointer',border:'2px dashed '+C.sr+'25',marginBottom:16}} onClick={()=>{}}>
        <span style={{fontSize:32}}>🛡️</span>
        <div style={{fontSize:16,fontWeight:900,color:C.sr,marginTop:4}}>Drop Module Files for Security Matching</div>
        <div style={{fontSize:11,color:C.ts}}>BCM · 95640 · RFHUB EEE · GPEC2A — compare keys, sync, patch VINs</div>
        {mods.length>0&&<Tag color={C.a3}>{mods.length} loaded</Tag>}
      </Card>
    </div>
    {/* Target VIN + banners */}
    {mods.length>0&&<><Card style={{marginBottom:12,padding:14}}>
      <div style={{fontSize:10,fontWeight:800,color:C.sr,letterSpacing:2,marginBottom:6}}>TARGET VIN</div>
      <input value={tv} maxLength={17} placeholder="17-char target VIN" onChange={e=>setTv(e.target.value.toUpperCase().replace(/[^A-HJ-NPR-Z0-9]/g,''))} style={{width:'100%',padding:'10px 14px',borderRadius:10,border:'2px solid '+C.bd,background:C.c2,fontFamily:"'JetBrains Mono'",fontSize:15,fontWeight:700,letterSpacing:3,textAlign:'center',outline:'none',boxSizing:'border-box',color:C.tx}} onFocus={e=>e.target.style.borderColor=C.sr} onBlur={e=>e.target.style.borderColor=C.bd}/>
      {vinBad&&tv.length===17&&<div style={{marginTop:8}}><Btn onClick={()=>mods.forEach((_,i)=>patchV(i))} full>⚡ Patch All Mismatched → {tv}</Btn></div>}
    </Card>
    <div style={{display:'flex',gap:6,marginBottom:12,flexWrap:'wrap'}}>
      <div style={{padding:'7px 12px',borderRadius:8,fontSize:11,fontWeight:800,background:vinBad?C.er+'10':C.gn+'10',color:vinBad?C.er:C.gn}}>{vinBad?'⚠ VIN MISMATCH — '+allV.length+' different':'✓ VINs Match'}</div>
      {sks.length>0&&<div style={{padding:'7px 12px',borderRadius:8,fontSize:11,fontWeight:800,background:skBad?C.er+'10':C.gn+'10',color:skBad?C.er:C.gn}}>{skBad?'⚠ KEY MISMATCH':'✓ Keys Match'}</div>}
    </div></>}
    {/* Module cards */}
    {mods.map((m,idx)=>{const vinOk=m.vins.length>0&&m.vins[0].vin===tv;return<Card key={idx} style={{marginBottom:12,borderColor:vinOk?C.gn+'50':m.vins.length&&tv.length===17?C.er+'40':C.bd}}>
      <div style={{display:'flex',alignItems:'center',gap:6,marginBottom:10}}>
        <Tag color={SKCOL[m.type]||C.tm}>{SKLBL[m.type]||m.type}</Tag>
        <span style={{flex:1,fontSize:12,fontWeight:700,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{m.fn}</span>
        <span style={{fontSize:10,color:C.tm}}>{(m.sz/1024).toFixed(0)}KB</span>
        <button onClick={()=>setMods(p=>p.filter((_,i)=>i!==idx))} style={{background:'none',border:'none',color:C.tm,cursor:'pointer',fontSize:14}}>✕</button>
      </div>
      {m.vins.length>0&&<div style={{padding:'8px 12px',borderRadius:8,marginBottom:8,background:vinOk?C.gn+'08':C.er+'06',border:'1px solid '+(vinOk?C.gn:C.er)+'20',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
        <div><span style={{fontSize:10,color:C.tm}}>VIN: </span><span style={{fontFamily:"'JetBrains Mono'",fontSize:14,fontWeight:900,letterSpacing:2,color:vinOk?C.gn:C.er}}>{m.vins[0].vin}</span>{m.vins[0].mir&&<Tag color={C.a3}>MIRRORED</Tag>}</div>
        <span style={{fontSize:10,fontWeight:800,color:vinOk?C.gn:C.er}}>{vinOk?'✓ MATCH':'✗'}</span>
      </div>}
      {m.skey&&<div style={{padding:'8px 12px',borderRadius:8,marginBottom:8,background:C.c2,border:'1px solid '+C.bd}}>
        <div style={{display:'flex',justifyContent:'space-between',marginBottom:4}}><span style={{fontSize:10,fontWeight:700}}>Secret Key @0x{m.skoff.toString(16).toUpperCase()}</span><Tag color={m.skb?C.wn:C.gn}>{m.skb?'ERASED':'SET'}</Tag></div>
        <div style={{fontFamily:"'JetBrains Mono'",fontSize:10,color:m.skb?'#D5D0C8':C.a4,wordBreak:'break-all'}}>{hxb(m.skey)}</div>
        {m.skb&&sks.length>0&&<div style={{marginTop:6,display:'flex',gap:4,flexWrap:'wrap'}}>{sks.filter(s=>s.idx!==idx).map(s=><Btn key={s.idx} onClick={()=>syncKey(s.idx,idx)} color={C.a4} outline>Copy from {SKLBL[s.type]}</Btn>)}</div>}
      </div>}
      {m.type==='bcm'&&<div style={{padding:'8px 12px',borderRadius:8,marginBottom:8,background:C.c2,border:'1px solid '+C.bd}}>
        <div style={{fontSize:10,marginBottom:4}}>Immo @0x40C0: <Tag color={m.immoBlank?C.wn:C.gn}>{m.immoBlank?'BLANK':'SET'}</Tag>{!m.immoBlank&&<Tag color={m.immoOk?C.gn:C.er}>Backup {m.immoOk?'✓':'MISMATCH'}</Tag>}</div>
        {!m.immoBlank&&<div style={{fontFamily:"'JetBrains Mono'",fontSize:9,color:C.a4,marginBottom:4}}>{hxb(m.immo)}</div>}
        <div style={{fontSize:10}}>Backup @0x2000: <Tag color={m.bakBlank?C.tm:C.gn}>{m.bakBlank?'BLANK':'SET'}</Tag></div>
      </div>}
      {m.type==='95640'&&<div style={{padding:'6px 12px',borderRadius:8,marginBottom:8,background:C.c2,border:'1px solid '+C.bd,fontSize:10}}>Fob Data: <Tag color={m.fobBlank?C.tm:C.gn}>{m.fobBlank?'NONE':'HAS FOBS'}</Tag></div>}
      {tv.length===17&&<Btn onClick={()=>patchV(idx)} full color={vinOk?C.gn:C.sr}>{vinOk?'↓ Download':'⚡ Patch → '+tv+' + Download'}</Btn>}
    </Card>;})}
    {/* SKIM grid */}
    {skimG.length>0&&<Card style={{marginTop:8}}><div style={{fontSize:14,fontWeight:800,marginBottom:10}}>🔐 SKIM Key Grid</div>
      {skimG.map((g,gi)=><div key={gi} style={{marginBottom:12}}><div style={{fontSize:12,fontWeight:800,color:C.a1,marginBottom:6}}>{g.v} — 0x{g.base.toString(16).toUpperCase()}</div>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:6}}>{g.keys.map(k=><div key={k.slot} style={{padding:10,borderRadius:10,background:C.c2,border:'1px solid '+(k.empty?C.bd:C.gn+'40')}}>
          <div style={{display:'flex',justifyContent:'space-between'}}><span style={{fontSize:10,fontWeight:700,color:C.tm}}>KEY {k.slot}</span><Tag color={k.empty?C.tm:C.gn}>{k.empty?'—':'SET'}</Tag></div>
          <div style={{fontFamily:"'JetBrains Mono'",fontSize:8,color:k.empty?'#D5D0C8':C.ts,marginTop:4,wordBreak:'break-all'}}>{k.hex}</div>
        </div>)}</div></div>)}
      <Btn onClick={()=>{let t='SKIM KEYS\n';skimG.forEach(g=>{t+=g.v+' @0x'+g.base.toString(16).toUpperCase()+'\n';g.keys.forEach(k=>{t+='  Key '+k.slot+': '+(k.empty?'EMPTY':k.hex)+'\n';});});navigator.clipboard?.writeText(t);setMsg('Copied');}} color={C.a1} outline>📋 Copy Keys</Btn>
    </Card>}
    {msg&&<div style={{marginTop:10,padding:'8px 12px',borderRadius:8,background:C.gn+'10',border:'1px solid '+C.gn+'25',fontSize:11,fontWeight:700,color:C.gn}}>✓ {msg}</div>}
    {!mods.length&&<div style={{textAlign:'center',padding:30,color:C.tm,fontSize:12}}>Drop BCM, RFHUB, 95640, GPEC2A files above to compare security</div>}
  </div>;
}


/* ═══════════════════════════════════════════════════════════════════════════
 * SRT LAB v2 — VEHICLE-FIRST NAVIGATION
 * New modules: catalog, engine wrappers, UI shell.
 * ═══════════════════════════════════════════════════════════════════════════ */

/* ═══ VEHICLE CATALOG ═══ */
/* Part numbers shared between gen1 (2011-2014) and gen2-split (2021+ Redeye/Scat Pack).
 * Disambiguation requires the VIN model-year character (10th VIN char, index 9).
 * Year chars J/K/L/M/N/P/R/S/T map to 2018+, so any 68525720/68525721 dump whose
 * parsed VIN has one of these chars is a gen2-split Redeye, not a gen1 module.
 * All helpers (VEHICLES, analyzeDumpPartNumber, generationForPartNumber, etc.) are
 * imported from ./lib/vehicles.js above. */

/* ═══ VEHICLE-AWARE SYNC ENGINE ═══ 
 * BCM/RFH/PCM parsing + writing for Gen2 (68396561 family) modules.
 * Older families fall back to the legacy helpers already in the file.
 */

const BCM_SLOT_TYPES=[0x46,0x52,0x53,0x56,0x57];
const VIN_REGEX=/^[12345][A-HJ-NPR-Z0-9]{16}$/;

function engCrc16(data,init=0xFFFF,poly=0x1021){let c=init;for(const b of data){c^=b<<8;for(let j=0;j<8;j++)c=c&0x8000?(((c<<1)^poly)&0xFFFF):((c<<1)&0xFFFF);}return c&0xFFFF;}

function engParseBcm(bytes){
  const r={kind:'BCM',size:bytes.length,partNumbers:[],vinSlots:[],shortVinSlots:[],sec16Records:[],sec16Mirrors:[],banks:[]};
  const text=new TextDecoder('latin1').decode(bytes);
  r.partNumbers=[...new Set([...text.matchAll(/68\d{6}/g)].map(m=>m[0]))];
  /* FULL VIN SLOTS */
  for(let i=0;i<bytes.length-21;i++){
    if(bytes[i]!==0x00||bytes[i+1]!==0x46)continue;
    if(!BCM_SLOT_TYPES.includes(bytes[i+2]))continue;
    if(bytes[i+3]!==0x00)continue;
    const vs=i+4;if(vs+19>bytes.length)continue;
    let vin='',valid=true;for(let k=0;k<17;k++){const b=bytes[vs+k];if(b<0x20||b>0x7E){valid=false;break;}vin+=String.fromCharCode(b);}
    if(!valid||!VIN_REGEX.test(vin))continue;
    const storedCrc=(bytes[vs+17]<<8)|bytes[vs+18];
    const computedCrc=engCrc16(bytes.slice(vs,vs+17));
    r.vinSlots.push({offset:vs,slotType:bytes[i+2],vin,storedCrc,computedCrc,crcOk:storedCrc===computedCrc});
  }
  /* SHORT VIN SLOTS */
  for(let i=0;i<bytes.length-14;i++){
    if(bytes[i]!==0x00||bytes[i+1]!==0x46)continue;
    if(bytes[i+3]!==0x00)continue;
    const vs=i+4;if(vs+10>bytes.length)continue;
    let isTail=true,tail='';for(let k=0;k<8;k++){const b=bytes[vs+k];if(!((b>=0x30&&b<=0x39)||(b>=0x41&&b<=0x5A))){isTail=false;break;}tail+=String.fromCharCode(b);}
    if(!isTail)continue;
    let looksFull=vs+17<=bytes.length;
    if(looksFull){for(let k=8;k<17;k++){const b=bytes[vs+k];if(!((b>=0x30&&b<=0x39)||(b>=0x41&&b<=0x5A))){looksFull=false;break;}}}
    if(looksFull)continue;
    const storedCrc=(bytes[vs+8]<<8)|bytes[vs+9];
    const computedCrc=engCrc16(bytes.slice(vs,vs+8));
    r.shortVinSlots.push({offset:vs,tail,storedCrc,computedCrc,crcOk:storedCrc===computedCrc});
  }
  /* SPLIT SEC16 RECORDS (bank 2 at 0x81A0/C0/E0, 7+9 format) */
  for(let i=0;i<bytes.length-32;i++){
    if(bytes[i]!==0xFF||bytes[i+1]!==0xFF)continue;
    let hdrOk=true;for(let j=2;j<8;j++)if(bytes[i+j]!==0x00){hdrOk=false;break;}
    if(!hdrOk)continue;
    const idx=bytes[i+8];if(idx!==0x01&&idx!==0x02)continue;
    if(bytes[i+16]!==0x04||bytes[i+17]!==0x04||bytes[i+18]!==0x00||bytes[i+19]!==0x14)continue;
    const prefix=bytes.slice(i+9,i+16);
    const suffix=bytes.slice(i+20,i+29);
    const sec16=new Uint8Array(16);sec16.set(prefix,0);sec16.set(suffix,7);
    r.sec16Records.push({offset:i,format:'split',idx,sec16,trailer:bytes[i+29]});
  }
  /* CONTIGUOUS MIRROR RECORDS (slot 0xEB size 0x18, slot 0xCA size 0x28) in either bank */
  const findMirrorsInBank=(bankBase,slotType,sizeByte,kind)=>{
    const bankEnd=Math.min(bankBase+0x4000,bytes.length);
    for(let i=bankBase;i<bankEnd-32;i++){
      if(bytes[i]===0x00&&bytes[i+1]===0x00&&bytes[i+2]===0x00&&
         bytes[i+3]===sizeByte&&bytes[i+4]===0x00&&bytes[i+5]===0x46&&
         bytes[i+6]===slotType&&bytes[i+7]===0x00){
        /* Check if data section is populated (not all zeros / not all FF) */
        const idx=bytes[i+8];
        const sec16=bytes.slice(i+9,i+25);
        const allZero=sec16.every(b=>b===0x00);
        const allFf=sec16.every(b=>b===0xFF);
        const storedCrc=(bytes[i+28]<<8)|bytes[i+29];
        /* Compute expected CRC over idx + SEC16 + trailer + FF + FF */
        const crcInput=new Uint8Array(20);
        crcInput[0]=idx;for(let k=0;k<16;k++)crcInput[1+k]=sec16[k];
        crcInput[17]=bytes[i+25];crcInput[18]=bytes[i+26];crcInput[19]=bytes[i+27];
        let crc=0xFFFF;for(let x=0;x<crcInput.length;x++){crc^=crcInput[x]<<8;for(let j=0;j<8;j++)crc=crc&0x8000?((crc<<1)^0x1021)&0xFFFF:(crc<<1)&0xFFFF;}
        const crcOk=crc===storedCrc;
        r.sec16Mirrors.push({offset:i,kind,slotType,sizeByte,idx,sec16,populated:!allZero&&!allFf,allZero,allFf,storedCrc,computedCrc:crc,crcOk,bank:bankBase===0?'bank0':'bank1'});
      }
    }
  };
  /* Scan both banks for mirrors */
  if(bytes.length>=0x8000){
    findMirrorsInBank(0x0000,0xEB,0x18,'mirror1');
    findMirrorsInBank(0x0000,0xCA,0x28,'mirror2');
    findMirrorsInBank(0x4000,0xEB,0x18,'mirror1');
    findMirrorsInBank(0x4000,0xCA,0x28,'mirror2');
  }
  /* Determine active/inactive banks */
  if(bytes.length>=0x8000){
    const bank0Seq=(bytes[0x0002]<<8)|bytes[0x0003];
    const bank1Seq=(bytes[0x4002]<<8)|bytes[0x4003];
    r.banks={bank0Seq,bank1Seq,activeBank:bank0Seq>=bank1Seq?0:1,inactiveBase:bank0Seq>=bank1Seq?0x4000:0x0000};
  }
  /* Summary fields */
  if(r.vinSlots.length>0){
    const c={};for(const s of r.vinSlots)c[s.vin]=(c[s.vin]||0)+1;
    r.vin=Object.entries(c).sort((a,b)=>b[1]-a[1])[0][0];
    r.vinConsistent=Object.keys(c).length===1;
  }
  if(r.sec16Records.length>0){
    const hx=r.sec16Records.map(x=>[...x.sec16].map(b=>b.toString(16).padStart(2,'0')).join(''));
    r.sec16Consistent=hx.every(h=>h===hx[0]);
    r.sec16Hex=hx[0];
  }
  /* Use populated mirror as canonical SEC16 if present */
  const populatedMirrors=r.sec16Mirrors.filter(m=>m.populated&&m.crcOk);
  if(populatedMirrors.length>0){
    const mirHex=[...populatedMirrors[0].sec16].map(b=>b.toString(16).padStart(2,'0')).join('');
    if(!r.sec16Hex)r.sec16Hex=mirHex;
    r.sec16MirrorHex=mirHex;
    r.mirrorsPopulated=populatedMirrors.length;
  }
  return r;
}

const RFH_VIN_OFFSETS=[0x0EA5,0x0EB9,0x0ECD,0x0EE1];

function engParseRfh(bytes){const r={kind:'RFHUB',size:bytes.length,vinSlots:[],sec16:null,format:'unknown'};
  for(const off of RFH_VIN_OFFSETS){if(off+18>bytes.length)continue;const raw=bytes.slice(off,off+17);const rev=new Uint8Array(17);for(let i=0;i<17;i++)rev[i]=raw[16-i];let vin='',valid=true;for(let i=0;i<17;i++){const b=rev[i];if(b<0x20||b>0x7E){valid=false;break;}vin+=String.fromCharCode(b);}if(!valid||!VIN_REGEX.test(vin))continue;const storedChk=bytes[off+17];let sum=0;for(const b of raw)sum=(sum+b)&0xFF;const computedChk=(0xF9-sum)&0xFF;r.vinSlots.push({offset:off,vin,storedChk,computedChk,chkOk:storedChk===computedChk});}
  if(r.vinSlots.length>0){r.vin=r.vinSlots[0].vin;r.vinConsistent=r.vinSlots.every(s=>s.vin===r.vin);}
  const gen2Hdr=bytes[0x0500]===0xAA&&bytes[0x0501]===0x55&&bytes[0x0502]===0x31&&bytes[0x0503]===0x01;
  const g2=bytes.slice(0x050E,0x051E),g1=bytes.slice(0x0226,0x0238);
  const g2Pop=!g2.every(b=>b===0xFF)&&!g2.every(b=>b===0x00);const g1Pop=!g1.every(b=>b===0xFF)&&!g1.every(b=>b===0x00);
  const aeq=(a,b)=>{if(!a||!b||a.length!==b.length)return false;for(let i=0;i<a.length;i++)if(a[i]!==b[i])return false;return true;};
  if(gen2Hdr&&g2Pop){r.format='gen2';r.sec16={slot1:bytes.slice(0x050E,0x051E),slot2:bytes.slice(0x0522,0x0532),virgin:g2.every(b=>b===0xFF)};r.sec16.match=aeq(r.sec16.slot1,r.sec16.slot2);}
  else if(g1Pop){r.format='gen1';r.sec16={slot1:bytes.slice(0x0226,0x0238),slot2:bytes.slice(0x023A,0x024C),virgin:g1.every(b=>b===0xFF)};r.sec16.match=aeq(r.sec16.slot1,r.sec16.slot2);}
  return r;
}

function engParsePcm(bytes){
  /* Continental GPEC2A — 4 KB or 8 KB EEPROM. The canonical immobilizer
   * slot is `FF FF FF AA` @ 0x3C4 + 6 secret bytes @ 0x3C8 on every real
   * BCM-paired dump (Task #404). There is no separate "GPEC5" variant —
   * the 8 KB image is just a larger GPEC2A. The pre-#404 marker scan
   * accepted any stray `FF FF FF FF` followed by a single non-FF byte
   * (e.g. the 0x00 at offset 0x19 on a virgin GPEC2A) and fabricated a
   * populated SEC6 from padding noise — that path is gone. */
  const r={kind:'PCM',size:bytes.length,vinSlots:[],sec6:null,currentVin:null,originalVin:null,variant:'GPEC2A'};
  /* VIN slots at known offsets */
  for(const off of PCM_VIN_OFFSETS_GPEC2A){if(off+17>bytes.length)continue;let vin='',valid=true;for(let k=0;k<17;k++){const b=bytes[off+k];if(b<0x20||b>0x7E){valid=false;break;}vin+=String.fromCharCode(b);}if(valid&&VIN_REGEX.test(vin))r.vinSlots.push({offset:off,vin});}
  if(r.vinSlots.length>0){r.vin=r.vinSlots[0].vin;r.vinConsistent=r.vinSlots.every(s=>s.vin===r.vin);
    /* SINCRO convention: first slot = CURRENT VIN, later slot = ORIGINAL VIN */
    r.currentVin = r.vinSlots[0].vin;
    if(r.vinSlots.length>1) r.originalVin = r.vinSlots[r.vinSlots.length-1].vin;
  }
  /* SEC6 — canonical GPEC2A slot only. Both the marker AND the 6 secret
   * bytes must be present for the slot to count as populated. */
  if(bytes.length >= 0x3CE){
    const markerOk = bytes[0x3C4]===0xFF && bytes[0x3C5]===0xFF && bytes[0x3C6]===0xFF && bytes[0x3C7]===0xAA;
    const sec6 = bytes.slice(0x3C8, 0x3CE);
    /* Use the shared classifyPcmSec6() classifier from parseModule.js
     * as the single source of truth (Task #404 follow-up). The pre-#404
     * inline rule (`!allFF && !all00`) diverged from the classifier on
     * mostly-FF SEC6 (e.g. FF FF 00 FF FF FF: classifier → Virgin, but
     * the inline rule falsely flagged it as populated). Aligning here
     * keeps this overview consistent with parseModule and crossValidate. */
    const cls = classifyPcmSec6(sec6);
    const sec6Populated = cls.populated;
    const paired = markerOk && sec6Populated;
    r.sec6 = {
      offset:0x3C8, bytes:sec6,
      marker: markerOk ? 'FF FF FF AA' : 'FF FF FF FF',
      markerOffset:0x3C4, markerOk,
      populated: sec6Populated,
    };
    r.immoDamaged = !paired;
  } else {
    r.immoDamaged = true;
  }
  /* immoOk and immoDamaged are strict logical inverses — `paired` from
   * the block above is the single source of truth. Pre-#404 immoOk was
   * derived independently from `!allFF`, which could yield contradictory
   * states (e.g. all-00 SEC6 with marker → immoDamaged AND immoOk). */
  r.immoOk = !!(r.sec6 && r.sec6.markerOk && r.sec6.populated);
  /* Continental PN (GPEC2A) */
  if(bytes.length>0x0FB0){const pnBytes=bytes.slice(0x0FA1,0x0FAE);const pn=new TextDecoder('latin1').decode(pnBytes);if(/^A2C\d/.test(pn))r.continentalPn=pn;}
  /* OS / PN / Serial strings — scan for ASCII patterns */
  const text=new TextDecoder('latin1').decode(bytes);
  const osMatch=text.match(/\b0[0-9]{7}[A-Z]{2}\b/); if(osMatch)r.osPn=osMatch[0];
  const bodyPn=text.match(/\b68[0-9]{6}[A-Z]{2}\b/); if(bodyPn)r.bodyPn=bodyPn[0];
  const serialMatch=text.match(/\bT[0-9]{2}[A-Z]{2}[0-9]{4}[A-Z]{2}[0-9]{3}\b/); if(serialMatch)r.serial=serialMatch[0];
  return r;
}

function engParseRfh24C32(bytes){
  /* 24C32 EEPROM RFH — 4KB Infineon EEPROM format used on some Chargers.
     Per SINCRO: VIN1/VIN2 with checksums, SEC1/SEC2 with CK, and a PIN field.
     Offsets below are best-guess from SINCRO screenshots; adjust when a real dump is on hand. */
  const r={kind:'RFH24C32',size:bytes.length,format:'24c32',vin1:null,vin2:null,sec1:null,sec2:null,pin:null,pinHex:null,warnings:[]};
  if(bytes.length!==4096){r.warnings.push('Not 4KB — may not be a 24C32 dump');return r;}
  /* VIN1 / VIN2 at fixed offsets (from SINCRO column widths — 17 bytes each with 2-byte CS after) */
  const v1Start=0x0000,v2Start=0x0020;
  r.vin1Hex=[...bytes.slice(v1Start,v1Start+17)].map(b=>b.toString(16).padStart(2,'0').toUpperCase()).join(' ');
  r.vin2Hex=[...bytes.slice(v2Start,v2Start+17)].map(b=>b.toString(16).padStart(2,'0').toUpperCase()).join(' ');
  const decode=(raw)=>{let s='',v=true;for(let k=0;k<17;k++){const b=raw[k];if(b<0x20||b>0x7E){v=false;break;}s+=String.fromCharCode(b);}return v&&VIN_REGEX.test(s)?s:null;};
  r.vin1=decode(bytes.slice(v1Start,v1Start+17));
  r.vin2=decode(bytes.slice(v2Start,v2Start+17));
  r.vinMatch=r.vin1&&r.vin2&&r.vin1===r.vin2;
  if(!r.vinMatch&&(r.vin1||r.vin2))r.warnings.push('VIN1 vs VIN2 mismatch');
  /* SEC16 copies */
  r.sec1=bytes.slice(0x100,0x110);
  r.sec2=bytes.slice(0x120,0x130);
  const aeq=(a,b)=>{if(a.length!==b.length)return false;for(let i=0;i<a.length;i++)if(a[i]!==b[i])return false;return true;};
  r.secMatch=aeq(r.sec1,r.sec2);
  if(!r.secMatch)r.warnings.push('SEC16 copies mismatch');
  /* PIN — SINCRO showed 3-byte hex. Likely location: offset 0x10D-0x10F (last 3 bytes of SEC1) */
  const pinBytes=bytes.slice(0x10D,0x110);
  r.pinHex=[...pinBytes].map(b=>b.toString(16).padStart(2,'0').toUpperCase()).join(' ');
  /* Convert 3-byte hex to 5-digit decimal PIN if valid (range check) */
  if(!pinBytes.every(b=>b===0xFF)){
    const pinNum=(pinBytes[0]<<16)|(pinBytes[1]<<8)|pinBytes[2];
    if(pinNum<100000)r.pin=pinNum.toString().padStart(5,'0');
    else r.pin='(out of range, raw hex: '+r.pinHex+')';
  }
  return r;
}

function engWriteBcmVin(bytes,newVin){if(!VIN_REGEX.test(newVin))throw new Error('Invalid VIN: '+newVin);const out=new Uint8Array(bytes);const vb=new TextEncoder().encode(newVin);const tb=vb.slice(9,17);const fullCrc=engCrc16(vb);const tailCrc=engCrc16(tb);let fullPatched=0,shortPatched=0;
  for(let i=0;i<out.length-21;i++){if(out[i]!==0x00||out[i+1]!==0x46)continue;if(!BCM_SLOT_TYPES.includes(out[i+2]))continue;if(out[i+3]!==0x00)continue;const vs=i+4;if(vs+19>out.length)continue;let curr='',valid=true;for(let k=0;k<17;k++){const b=out[vs+k];if(b<0x20||b>0x7E){valid=false;break;}curr+=String.fromCharCode(b);}if(!valid||!VIN_REGEX.test(curr))continue;for(let k=0;k<17;k++)out[vs+k]=vb[k];out[vs+17]=(fullCrc>>8)&0xFF;out[vs+18]=fullCrc&0xFF;fullPatched++;}
  for(let i=0;i<out.length-14;i++){if(out[i]!==0x00||out[i+1]!==0x46)continue;if(out[i+3]!==0x00)continue;const vs=i+4;if(vs+10>out.length)continue;let isTail=true;for(let k=0;k<8;k++){const b=out[vs+k];if(!((b>=0x30&&b<=0x39)||(b>=0x41&&b<=0x5A))){isTail=false;break;}}if(!isTail)continue;let looksFull=vs+17<=out.length;if(looksFull){for(let k=8;k<17;k++){const b=out[vs+k];if(!((b>=0x30&&b<=0x39)||(b>=0x41&&b<=0x5A))){looksFull=false;break;}}}if(looksFull)continue;for(let k=0;k<8;k++)out[vs+k]=tb[k];out[vs+8]=(tailCrc>>8)&0xFF;out[vs+9]=tailCrc&0xFF;shortPatched++;}
  return{bytes:out,fullPatched,shortPatched,fullCrc,tailCrc};
}

/* engWritePcmSec6 / writeRfhSec16FromBcm — single source of truth in
 * lib/securityBytes.js (golden-vector regression test in
 * lib/__tests__/securityBytes.golden.test.js). The BCM SEC16 writer is no
 * longer aliased here: SYNC ALL MODULES treats the BCM as the source of
 * truth and never overwrites the BCM secret. */

function engWriteRfhVin(bytes,newVin,virginize){if(!VIN_REGEX.test(newVin))throw new Error('Invalid VIN: '+newVin);const out=new Uint8Array(bytes);const fwd=new TextEncoder().encode(newVin);const rev=new Uint8Array(17);for(let i=0;i<17;i++)rev[i]=fwd[16-i];let sum=0;for(const b of rev)sum=(sum+b)&0xFF;const chk=(0xF9-sum)&0xFF;let patched=0;
  for(const off of RFH_VIN_OFFSETS){if(off+18>out.length)continue;for(let k=0;k<17;k++)out[off+k]=rev[k];out[off+17]=chk;patched++;}
  let sec16Wiped=0;
  if(virginize){const gen2Hdr=out[0x0500]===0xAA&&out[0x0501]===0x55;if(gen2Hdr){for(const so of [0x050E,0x0522]){for(let k=0;k<18;k++)out[so+k]=0xFF;sec16Wiped++;}}else{for(const so of [0x0226,0x023A]){for(let k=0;k<18;k++)out[so+k]=0xFF;sec16Wiped++;}}}
  return{bytes:out,patched,sec16Wiped,chk};
}

const engWritePcmSec6 = writePcmSec6;

function engWritePcmVin(bytes,newVin){if(!VIN_REGEX.test(newVin))throw new Error('Invalid VIN: '+newVin);const out=new Uint8Array(bytes);const vb=new TextEncoder().encode(newVin);let patched=0;for(const off of PCM_VIN_OFFSETS_GPEC2A){if(off+17>out.length)continue;for(let k=0;k<17;k++)out[off+k]=vb[k];patched++;}return{bytes:out,patched};}

const hexStr=(arr)=>[...arr].map(b=>b.toString(16).padStart(2,'0')).join('');
const u8FromHex=(h)=>{const s=(h||'').replace(/[^0-9a-fA-F]/g,'');const n=s.length>>1;const a=new Uint8Array(n);for(let i=0;i<n;i++)a[i]=parseInt(s.substr(i*2,2),16);return a;};

